    43→    pub fn human_move(&mut self, human_like: bool) -> Result<(), String> {
    44→        let start = self.get_position()?;
    45→        let mut rng = rng();
    46→
    47→        // Random distance: 5-50 pixels
    48→        let distance: f64 = rng.gen_range(5.0..50.0);
    49→        let angle: f64 = rng.gen_range(0.0..std::f64::consts::TAU);
    50→
    51→        let end = Point::new(
    52→            start.x + distance * angle.cos(),
    53→            start.y + distance * angle.sin(),
    54→        );
    55→
    56→        if human_like {
    57→            self.bezier_move(start, end)?;
    58→        } else {
    59→            self.move_to(end.x as i32, end.y as i32)?;
    60→        }
    61→
    62→        // Small delay before returning
    63→        let return_delay = rng.gen_range(50..150);
    64→        thread::sleep(Duration::from_millis(return_delay));
    65→
    66→        // Return to original position (also with human-like movement)
    67→        if human_like {
    68→            self.bezier_move(end, start)?;
    69→        } else {
    70→            self.move_to(start.x as i32, start.y as i32)?;
    71→        }
    72→
    73→        Ok(())
    74→    }
    75→
    76→    fn bezier_move(&mut self, start: Point, end: Point) -> Result<(), String> {
    77→        let mut rng = rng();
    78→
    79→        // Generate control points for cubic Bézier curve
    80→        let mid_x = (start.x + end.x) / 2.0;
    81→        let mid_y = (start.y + end.y) / 2.0;
    82→        let deviation = 30.0;
    83→
    84→        let ctrl1 = Point::new(
    85→            mid_x + rng.gen_range(-deviation..deviation),
    86→            mid_y + rng.gen_range(-deviation..deviation),
    87→        );
    88→        let ctrl2 = Point::new(
    89→            mid_x + rng.gen_range(-deviation..deviation),
    90→            mid_y + rng.gen_range(-deviation..deviation),
    91→        );
    92→
    93→        // Number of steps (more steps = smoother movement)
    94→        let steps: u32 = rng.gen_range(25..40);
    95→        let step_delay = rng.gen_range(5..15);
    96→
    97→        for i in 0..=steps {
    98→            let t = i as f64 / steps as f64;
    99→
   100→            // Apply easing (ease-in-out)
   101→            let t_eased = ease_in_out(t);
   102→
   103→            let point = cubic_bezier(t_eased, start, ctrl1, ctrl2, end);
   104→
   105→            // Add micro-tremor (Gaussian-like noise)
   106→            let tremor_x = rng.gen_range(-0.5..0.5);
   107→            let tremor_y = rng.gen_range(-0.5..0.5);
   108→
   109→            self.move_to(
   110→                (point.x + tremor_x) as i32,
   111→                (point.y + tremor_y) as i32,
   112→            )?;
   113→
   114→            thread::sleep(Duration::from_millis(step_delay));
   115→        }
   116→
   117→        // Occasional overshoot (10% chance)
   118→        if rng.gen_bool(0.1) {
   119→            let overshoot = rng.gen_range(2.0..5.0);
   120→            let overshoot_point = Point::new(
   121→                end.x + overshoot * (end.x - start.x).signum(),
   122→                end.y + overshoot * (end.y - start.y).signum(),
   123→            );
   124→            self.move_to(overshoot_point.x as i32, overshoot_point.y as i32)?;
   125→            thread::sleep(Duration::from_millis(30));
   126→            self.move_to(end.x as i32, end.y as i32)?;
   127→        }
   128→
   129→        Ok(())
   130→    }
   131→}
   132→
   133→fn cubic_bezier(t: f64, p0: Point, p1: Point, p2: Point, p3: Point) -> Point {
   134→    let u = 1.0 - t;
   135→    let tt = t * t;
   136→    let uu = u * u;
   137→    let uuu = uu * u;
   138→    let ttt = tt * t;
   139→
   140→    Point {
   141→        x: uuu * p0.x + 3.0 * uu * t * p1.x + 3.0 * u * tt * p2.x + ttt * p3.x,
   142→        y: uuu * p0.y + 3.0 * uu * t * p1.y + 3.0 * u * tt * p2.y + ttt * p3.y,
   143→    }
   144→}
   145→
   146→fn ease_in_out(t: f64) -> f64 {
   147→    if t < 0.5 {
   148→        2.0 * t * t
   149→    } else {
   150→        1.0 - (-2.0 * t + 2.0).powi(2) / 2.0
   151→    }
   152→}
